export const usePaymentModule = () => {
  const [iapReady, setIapReady] = useState(false);
  const [iapError, setIapError] = useState(null);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        await PaymentModule.initIap();
        if (mounted) setIapReady(true);
      } catch (e) {
        if (mounted) setIapError(e);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const refreshPurchases = useCallback(async () => {
    return await PaymentModule.getAvailablePurchases();
  }, []);

  return useMemo(
    () => ({
      iapReady,
      iapError,
      refreshPurchases,
      api: PaymentModule,
    }),
    [iapReady, iapError, refreshPurchases]
  );
};

export const PaymentButton = ({
  title = 'Pay',
  disabled,
  onPress,
  style,
  textStyle,
  testID,
}) => {
  return (
    <TouchableOpacity
      testID={testID}
      accessibilityRole="button"
      onPress={onPress}
      disabled={disabled}
      style={[styles.btn, disabled ? styles.btnDisabled : null, style]}
    >
      <Text style={[styles.btnText, textStyle]}>{title}</Text>
    </TouchableOpacity>
  );
};

export const ExamplePurchaseView = ({
  productId,
  userId,
  validateWithBackend = true,
  consumable = false,
}) => {
  const [busy, setBusy] = useState(false);
  const [status, setStatus] = useState('');
  const mountedRef = useRef(true);

  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
    };
  }, []);

  const setSafeStatus = (s) => {
    if (mountedRef.current) setStatus(s);
  };

  const buy = useCallback(async () => {
    setBusy(true);
    setSafeStatus('Starting purchase...');
    try {
      const { purchase, idempotencyKey } = await PaymentModule.requestPurchase({ productId });
      setSafeStatus('Purchase received. Validating...');
      let validation = null;
      if (validateWithBackend) {
        validation = await PaymentModule.validateIapReceiptWithBackend({
          purchase,
          productId,
          idempotencyKey,
          userId,
        });
      }
      setSafeStatus('Finishing transaction...');
      await PaymentModule.finishTransaction(purchase, { isConsumable: consumable });
      setSafeStatus('Done');
      Alert.alert('Payment', 'Purchase completed');
      return { purchase, validation };
    } catch (e) {
      const code = e?.code || 'UNKNOWN';
      setSafeStatus(`Failed: ${code}`);
      if (code !== PaymentErrorCodes.CANCELLED) Alert.alert('Payment error', `${code}: ${e?.message || 'Unknown error'}`);
      throw e;
    } finally {
      setBusy(false);
    }
  }, [productId, userId, validateWithBackend, consumable]);

  return (
    <View style={styles.card}>
      <Text style={styles.title}>In-App Purchase</Text>
      <Text style={styles.label}>Product: {productId}</Text>
      <Text style={styles.status}>Status: {status || 'Idle'}</Text>
      <PaymentButton title={busy ? 'Processing...' : 'Buy'} disabled={busy || !productId} onPress={buy} />
    </View>
  );
};

